def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    if n <= 2:
        return sum(nums[1:-1]) / (n-2) if n > 1 else None

    median_index = int((len(nums)-1)/2)
    min_idx = nums[:median_index].rfind(nums[median_index]) + median_index
    max_idx = nums[-median_index-1:].find(nums[median_index]) + median_index
    return sum(nums[min_idx+1:max_idx-1]) / (n - 4)
